diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 73ba0f78e805..0345afde7789 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3291,7 +3291,11 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
       // Change: A = select B, C, false --> A = and B, C
       return BinaryOperator::CreateAnd(CondVal, TrueVal);
     }
-
+    // select (xor (trunc (lshr X, 31)), true), (icmp slt X, 0), false -> false
+    Value *X;
+    if (match(CondVal, m_c_Xor(m_Trunc(m_LShr(m_Value(X), m_SpecificInt(31))), m_One())) &&
+        match(TrueVal, m_SpecificICmp(ICmpInst::ICMP_SLT, m_Specific(X), m_Zero())))
+      return replaceInstUsesWith(SI, FalseVal);
     if (match(CondVal, m_OneUse(m_Select(m_Value(A), m_Value(B), m_Zero()))) &&
         impliesPoisonOrCond(TrueVal, B, /*Expected=*/true)) {
       // (A && B) && C --> A && (B & C)
@@ -4447,6 +4451,18 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
   if (CondVal->getType() == SI.getType() && isKnownInversion(FalseVal, TrueVal))
     return BinaryOperator::CreateXor(CondVal, FalseVal);

+  // select (not Cond), Cond, false -> false
+  // select (not Cond), true, Cond -> true
+  if (CondVal->getType() == SI.getType()) {
+    Value *NotCond = getFreelyInverted(CondVal, CondVal->hasOneUse(), &Builder);
+    if (NotCond) {
+      if (match(FalseVal, m_Zero()) && TrueVal == NotCond)
+        return replaceInstUsesWith(SI, ConstantInt::getFalse(SelType));
+      if (match(TrueVal, m_One()) && FalseVal == NotCond)
+        return replaceInstUsesWith(SI, ConstantInt::getTrue(SelType));
+    }
+  }
+
   // For vectors, this transform is only safe if the simplification does not
   // look through any lane-crossing operations. For now, limit to scalars only.
   if (SelType->isIntegerTy() &&

log.expect_optimized_program:
define i32 @not_d_allSignBits(i32 %cond, i32 %tval, i32 %fval) {
  %1 = icmp slt i32 %cond, 0
  %2 = xor i32 %fval, -1
  %sel = select i1 %1, i32 %tval, i32 %2
  ret i32 %sel
}

log.current_optimized_program:
define i32 @not_d_allSignBits(i32 %cond, i32 %tval, i32 %fval) {
  %1 = xor i32 %fval, -1
  %.not2 = icmp slt i32 %cond, 0
  %sel = select i1 %.not2, i32 %tval, i32 %1
  ret i32 %sel
}

